  1→import { useState, useEffect } from 'react';
  2→import {
  3→  LineChart,
  4→  Line,
  5→  XAxis,
  6→  YAxis,
  7→  CartesianGrid,
  8→  Tooltip,
  9→  Legend,
 10→  ResponsiveContainer,
 11→  ReferenceLine,
 12→} from 'recharts';
 13→import { format } from 'date-fns';
 14→import type { LoanSummary, AmortizationResult } from '../../types/loan';
 15→import { formatCurrency, formatCurrencyShort, formatDate } from '../../utils/formatters';
 16→
 17→interface Props {
 18→  summary: LoanSummary;
 19→  simulatedResult?: AmortizationResult | null;
 20→}
 21→
 22→const useIsMobile = () => {
 23→  const [isMobile, setIsMobile] = useState(false);
 24→  useEffect(() => {
 25→    const check = () => setIsMobile(window.innerWidth < 640);
 26→    check();
