 33→export const BalanceChart = ({ summary, simulatedResult }: Props) => {
 34→  const { withPrePayments, withoutPrePayments } = summary;
 35→  const isMobile = useIsMobile();
 36→
 37→  const currentMonthKey = format(new Date(), 'yyyy-MM');
 38→
 39→  const maxLen = Math.max(
 40→    withPrePayments.schedule.length,
 41→    withoutPrePayments.schedule.length,
 42→    simulatedResult?.schedule.length ?? 0,
 43→  );
 44→
 45→  let currentMonthIndex: number | null = null;
 46→
 47→  const data = Array.from({ length: maxLen }, (_, i) => {
 48→    const dateStr =
 49→      withoutPrePayments.schedule[i]?.date ??
 50→      withPrePayments.schedule[i]?.date ??
 51→      simulatedResult?.schedule[i]?.date ??
 52→      '';
 53→    const monthKey = dateStr.substring(0, 7);
 54→    if (monthKey === currentMonthKey) {
 55→      currentMonthIndex = i + 1;
 56→    }
 57→    const entry: Record<string, number | string> = {
 58→      month: i + 1,
 59→      label: dateStr ? formatDate(dateStr) : '',
 60→      withoutPP: withoutPrePayments.schedule[i]?.closingBalance ?? 0,
 61→      withPP: withPrePayments.schedule[i]?.closingBalance ?? 0,
 62→    };
 63→    if (simulatedResult) {
 64→      entry.simulated = simulatedResult.schedule[i]?.closingBalance ?? 0;
 65→    }
 66→    return entry;
 67→  });
 68→
 69→  return (
 70→    <div className="rounded-2xl border border-slate-200 bg-white p-4 sm:p-6 shadow-sm">
 71→      <h3 className="mb-3 sm:mb-4 text-base sm:text-lg font-bold text-slate-900">Outstanding Balance</h3>
 72→      <ResponsiveContainer width="100%" height={isMobile ? 260 : 350}>
 73→        <LineChart data={data} margin={isMobile ? { left: -10, right: 5, top: 5, bottom: 5 } : undefined}>
 74→          <CartesianGrid strokeDasharray="3 3" stroke="#f1f5f9" />
 75→          <XAxis
 76→            dataKey="month"
 77→            tick={{ fontSize: isMobile ? 10 : 12 }}
 78→            label={isMobile ? undefined : { value: 'Month', position: 'insideBottom', offset: -5 }}
 79→          />
 80→          <YAxis
 81→            tickFormatter={(v) => formatCurrencyShort(v)}
 82→            width={isMobile ? 55 : 80}
 83→            tick={{ fontSize: isMobile ? 10 : 12 }}
 84→          />
 85→          <Tooltip
 86→            formatter={(value) => formatCurrency(Number(value))}
 87→            labelFormatter={(_: unknown, payload: readonly { payload?: { label?: string } }[]) =>
 88→              payload?.[0]?.payload?.label || ''
 89→            }
 90→            contentStyle={{ fontSize: 12, borderRadius: 12, border: '1px solid #e2e8f0', boxShadow: '0 4px 12px rgba(0,0,0,0.08)' }}
 91→          />
 92→          <Legend
 93→            iconSize={isMobile ? 8 : 14}
 94→            wrapperStyle={{ fontSize: isMobile ? 10 : 12, paddingTop: 8 }}
 95→          />
 96→          {currentMonthIndex !== null && (
 97→            <ReferenceLine
 98→              x={currentMonthIndex}
 99→              stroke="#2563eb"
100→              strokeWidth={2}
101→              strokeDasharray="4 4"
102→              label={isMobile ? undefined : { value: 'Now', position: 'top', fill: '#2563eb', fontWeight: 'bold' }}
103→            />
104→          )}
105→          <Line
106→            type="monotone"
107→            dataKey="withoutPP"
108→            name="Original"
109→            stroke="#94a3b8"
110→            strokeWidth={2}
111→            dot={false}
112→          />
113→          <Line
114→            type="monotone"
115→            dataKey="withPP"
116→            name="Actual"
117→            stroke="#2563eb"
118→            strokeWidth={2}
119→            dot={false}
120→          />
121→          {simulatedResult && (
122→            <Line
123→              type="monotone"
124→              dataKey="simulated"
125→              name="Simulated"
126→              stroke="#f59e0b"
127→              strokeWidth={2}
128→              strokeDasharray="6 3"
129→              dot={false}
130→            />
131→          )}
132→        </LineChart>
133→      </ResponsiveContainer>
134→    </div>
135→  );
136→};
