31→export const YearlySummaryChart = ({ schedule, isSimulated }: Props) => {
32→  const isMobile = useIsMobile();
33→  const yearMap = new Map<string, { interest: number; principal: number }>();
34→
35→  for (const row of schedule) {
36→    const year = row.date.substring(0, 4);
37→    const existing = yearMap.get(year) || { interest: 0, principal: 0 };
38→    existing.interest += row.interestComponent;
39→    existing.principal += row.principalComponent + row.prePayment;
40→    yearMap.set(year, existing);
41→  }
42→
43→  const data = Array.from(yearMap.entries()).map(([year, vals]) => ({
44→    year: isMobile ? `'${year.slice(2)}` : year,
45→    interest: Math.round(vals.interest),
46→    principal: Math.round(vals.principal),
47→  }));
48→
49→  return (
50→    <div className="rounded-2xl border border-slate-200 bg-white p-4 sm:p-6 shadow-sm">
51→      <h3 className="mb-3 sm:mb-4 text-base sm:text-lg font-bold text-slate-900">
52→        Yearly Summary
53→        {isSimulated && (
54→          <span className="ml-2 text-sm font-normal text-amber-600">(simulated)</span>
55→        )}
56→      </h3>
57→      <ResponsiveContainer width="100%" height={isMobile ? 260 : 350}>
58→        <BarChart data={data} margin={isMobile ? { left: -10, right: 5, top: 5, bottom: 5 } : undefined}>
59→          <CartesianGrid strokeDasharray="3 3" stroke="#f1f5f9" />
60→          <XAxis
61→            dataKey="year"
62→            tick={{ fontSize: isMobile ? 10 : 12 }}
63→            interval={isMobile && data.length > 10 ? 1 : 0}
64→          />
65→          <YAxis
66→            tickFormatter={(v) => formatCurrencyShort(v)}
67→            width={isMobile ? 45 : 80}
68→            tick={{ fontSize: isMobile ? 10 : 12 }}
69→          />
70→          <Tooltip
71→            formatter={(value) => formatCurrency(Number(value))}
72→            labelFormatter={(label) => `Year ${label}`}
73→            contentStyle={{ fontSize: 12, borderRadius: 12, border: '1px solid #e2e8f0', boxShadow: '0 4px 12px rgba(0,0,0,0.08)' }}
74→          />
75→          <Legend
76→            iconSize={isMobile ? 8 : 14}
77→            wrapperStyle={{ fontSize: isMobile ? 10 : 12, paddingTop: 8 }}
78→          />
79→          <Bar dataKey="principal" name="Principal + Prepay" fill="#22c55e" radius={[0, 0, 0, 0]} />
80→          <Bar dataKey="interest" name="Interest" fill="#ef4444" radius={[4, 4, 0, 0]} />
