 6→export const useAmortization = (
 7→  loan: LoanInput | null,
 8→  prePayments: PrePayment[],
 9→  rateChanges: RateChange[] = [],
10→): { summary: LoanSummary | null; error: string | null } =>
11→  useMemo(() => {
12→    if (!loan) return { summary: null, error: null };
13→
14→    const validationError = validateLoan(loan);
15→    if (validationError) return { summary: null, error: validationError };
16→
17→    try {
18→      const summary = generateSummary(loan, prePayments, rateChanges);
19→      return { summary, error: null };
20→    } catch (e) {
21→      return { summary: null, error: (e as Error).message };
22→    }
23→  }, [loan, prePayments, rateChanges]);
