 79→              {hasRateChanges && <th className="py-3 px-3 text-right">Rate</th>}
 80→              <th className="py-3 px-3 text-right">Opening</th>
 81→              <th className="py-3 px-3 text-right">Interest</th>
 82→              <th className="py-3 px-3 text-right">Principal</th>
 83→              <th className="py-3 px-3 text-right">Pre-Pay</th>
 84→              <th className="py-3 px-3 text-right">Total</th>
 85→              <th className="py-3 px-3 text-right">Cum. Interest</th>
 86→              <th className="py-3 px-3 text-right">Cum. Principal</th>
 87→              <th className="py-3 px-3 text-right">Closing</th>
 88→            </tr>
 89→          </thead>
 90→          <tbody>
 91→            {(() => {
 92→              let cumulativeInterest = 0;
 93→              let cumulativePrincipal = 0;
 94→              return schedule.map((row) => {
 95→                cumulativeInterest += row.interestComponent;
 96→                cumulativePrincipal += row.principalComponent + row.prePayment;
 97→                const rowMonthKey = row.date.substring(0, 7);
 98→                const isCurrentMonth = rowMonthKey === currentMonthKey;
 99→                const rateChanged =
100→                  hasRateChanges &&
101→                  row.month > 1 &&
102→                  row.annualRate !== schedule[row.month - 2]?.annualRate;
103→                const isPlannedPP = plannedPPMonths?.has(rowMonthKey) && row.prePayment > 0;
104→
105→                let rowClass = 'border-b border-slate-50 transition-colors hover:bg-slate-50/80';
106→                if (isCurrentMonth) {
107→                  rowClass = 'bg-blue-50 border-b border-blue-100 ring-1 ring-inset ring-blue-200';
108→                } else if (isPlannedPP) {
109→                  rowClass =
110→                    'bg-amber-50/60 border-b border-amber-100 border-l-2 border-l-amber-400';
111→                } else if (row.prePayment > 0) {
112→                  rowClass = 'bg-emerald-50/40 border-b border-emerald-50';
113→                } else if (rateChanged) {
114→                  rowClass = 'bg-indigo-50/40 border-b border-indigo-50';
115→                }
116→
117→                return (
118→                  <tr
119→                    key={row.month}
120→                    ref={isCurrentMonth ? currentRowRef : undefined}
121→                    className={rowClass}
122→                  >
123→                    <td className="py-2.5 px-4 text-slate-400 text-xs">
124→                      {isCurrentMonth ? (
125→                        <span className="inline-flex items-center gap-1.5">
126→                          {row.month}
127→                          <span className="rounded-md bg-blue-600 px-1.5 py-0.5 text-[9px] font-bold text-white leading-none">
128→                            NOW
129→                          </span>
130→                        </span>
131→                      ) : isPlannedPP ? (
132→                        <span className="inline-flex items-center gap-1.5">
133→                          {row.month}
134→                          <span className="rounded-md bg-amber-500 px-1.5 py-0.5 text-[9px] font-bold text-white leading-none">
135→                            PLAN
136→                          </span>
137→                        </span>
138→                      ) : (
139→                        row.month
140→                      )}
141→                    </td>
142→                    <td className="py-2.5 px-3 whitespace-nowrap text-xs">
143→                      {formatDate(row.date)}
144→                    </td>
145→                    {hasRateChanges && (
146→                      <td
147→                        className={`py-2.5 px-3 text-right tabular-nums text-xs ${rateChanged ? 'font-bold text-indigo-600' : 'text-slate-400'}`}
148→                      >
149→                        {row.annualRate}%
150→                      </td>
151→                    )}
152→                    <td className="py-2.5 px-3 text-right tabular-nums text-xs">
153→                      {formatCurrency(row.openingBalance)}
154→                    </td>
155→                    <td className="py-2.5 px-3 text-right tabular-nums text-xs text-rose-600">
156→                      {formatCurrency(row.interestComponent)}
157→                    </td>
158→                    <td className="py-2.5 px-3 text-right tabular-nums text-xs text-emerald-600">
159→                      {formatCurrency(row.principalComponent)}
160→                    </td>
161→                    <td className="py-2.5 px-3 text-right tabular-nums text-xs">
162→                      {row.prePayment > 0 ? (
163→                        <span
164→                          className={`font-semibold ${isPlannedPP ? 'text-amber-600' : 'text-blue-600'}`}
165→                        >
166→                          {formatCurrency(row.prePayment)}
167→                        </span>
168→                      ) : (
169→                        <span className="text-slate-200">-</span>
170→                      )}
171→                    </td>
172→                    <td className="py-2.5 px-3 text-right tabular-nums text-xs font-medium">
173→                      {formatCurrency(row.totalPayment)}
174→                    </td>
175→                    <td className="py-2.5 px-3 text-right tabular-nums text-xs text-rose-500">
176→                      {formatCurrency(cumulativeInterest)}
177→                    </td>
178→                    <td className="py-2.5 px-3 text-right tabular-nums text-xs text-emerald-600">
179→                      {formatCurrency(cumulativePrincipal)}
180→                    </td>
181→                    <td className="py-2.5 px-3 text-right tabular-nums text-xs font-bold text-slate-700">
182→                      {formatCurrency(row.closingBalance)}
183→                    </td>
184→                  </tr>
185→                );
186→              });
187→            })()}
188→          </tbody>
189→        </table>
190→      </div>
191→    </div>
192→  );
193→};
