189→            <Tooltip
190→              content={<CustomTooltip />}
191→              cursor={{ fill: 'rgba(148, 163, 184, 0.1)', radius: 4 }}
192→            />
193→            <Legend content={renderLegend} />
194→            <Bar dataKey="Actual" fill={BAR_COLORS.Actual.fill} radius={[6, 6, 0, 0]} />
195→            {hasSimulated && (
196→              <Bar dataKey="Simulated" fill={BAR_COLORS.Simulated.fill} radius={[6, 6, 0, 0]} />
197→            )}
198→          </BarChart>
199→        </ResponsiveContainer>
200→      </div>
201→    </div>
202→  );
203→};
