  1→import OpenAI from 'openai';
  2→import type { ChatRequest, ScenarioIntent } from '@/types/chat';
  3→import { buildEnrichedContext, hasWhatIfKeywords, computeScenario } from '@/utils/chatContext';
  4→
  5→const openai = new OpenAI({
  6→  apiKey: process.env.OPENAI_API_KEY,
  7→});
  8→
  9→const detectScenarioIntent = async (
 10→  userMessage: string,
 11→): Promise<ScenarioIntent> => {
 12→  const response = await openai.chat.completions.create({
 13→    model: 'gpt-4o-mini',
 14→    messages: [
 15→      {
 16→        role: 'system',
 17→        content: `You classify loan-related messages. Determine if the user is asking a what-if or goal-based scenario question.
 18→
 19→Return JSON with this structure:
 20→{
 21→  "type": "none" | "prepayment_whatif" | "rate_change_whatif" | "target_closure",
 22→  "prepaymentAmount": <number in rupees if applicable, null otherwise>,
 23→  "prepaymentDate": <"YYYY-MM-DD" if user specifies when, null otherwise>,
 24→  "newRate": <number if rate change scenario, null otherwise>,
 25→  "rateChangeDate": <"YYYY-MM-DD" if specified, null otherwise>,
 26→  "targetYears": <number of years if target closure, null otherwise>
 27→}
 28→
 29→Rules:
 30→- "prepayment_whatif": user asks about making an extra/lump-sum payment. Convert lakhs to rupees (1 lakh = 100000).
 31→- "rate_change_whatif": user asks about interest rate changing.
 32→- "target_closure": user wants to know how to close/complete/finish/pay off the loan within a specific timeframe (e.g. "close in 5 years", "complete within 3 years", "how to finish my loan in 2 years"). Extract the number of years.
 33→- "none": any other question (even if it mentions pre-payments that already exist).
 34→- For relative dates like "next month", use today's date as reference and compute the approximate date.
 35→- Today's date: ${new Date().toISOString().split('T')[0]}`,
 36→      },
 37→      { role: 'user', content: userMessage },
 38→    ],
 39→    response_format: { type: 'json_object' },
 40→    max_tokens: 150,
 41→  });
 42→
 43→  try {
 44→    const parsed = JSON.parse(response.choices[0]?.message?.content || '{}');
 45→    return {
 46→      type: parsed.type || 'none',
 47→      prepaymentAmount: parsed.prepaymentAmount ?? undefined,
 48→      prepaymentDate: parsed.prepaymentDate ?? undefined,
 49→      newRate: parsed.newRate ?? undefined,
 50→      rateChangeDate: parsed.rateChangeDate ?? undefined,
 51→      targetYears: parsed.targetYears ?? undefined,
 52→    };
 53→  } catch {
 54→    return { type: 'none' };
 55→  }
 56→};
 57→
 58→export const POST = async (request: Request) => {
 59→  try {
 60→    const body: ChatRequest = await request.json();
 61→    const { messages, loan, prePayments, rateChanges } = body;
 62→
 63→    if (!messages || messages.length === 0) {
 64→      return new Response(JSON.stringify({ error: 'Messages are required' }), {
 65→        status: 400,
 66→        headers: { 'Content-Type': 'application/json' },
 67→      });
 68→    }
 69→
 70→    // Build enriched context from full amortization engine
 71→    const enrichedContext = buildEnrichedContext(loan, prePayments, rateChanges);
 72→
 73→    // Detect and compute what-if scenarios
 74→    const latestUserMessage = messages[messages.length - 1]?.content || '';
 75→    let scenarioData: string | null = null;
 76→
 77→    if (hasWhatIfKeywords(latestUserMessage)) {
 78→      const intent = await detectScenarioIntent(latestUserMessage);
 79→      scenarioData = computeScenario(intent, loan, prePayments, rateChanges);
 80→    }
 81→
 82→    const systemPrompt = `You are a helpful loan advisor assistant. All data below is pre-computed by an accurate amortization engine. Use these numbers directly. NEVER perform your own calculations or estimate numbers — only present the pre-computed data below.
 83→
 84→=== LOAN SUMMARY ===
 85→${enrichedContext.summary}
 86→
 87→=== CURRENT STATUS (as of today) ===
 88→${enrichedContext.currentStatus}
 89→
 90→=== YEARLY BREAKDOWN ===
 91→${enrichedContext.yearlyBreakdown}
 92→
 93→=== PRE-PAYMENT DETAILS ===
 94→${enrichedContext.prePaymentDetails}
 95→
 96→=== RATE CHANGE TIMELINE ===
 97→${enrichedContext.rateChangeTimeline}
 98→
 99→=== MILESTONES ===
100→${enrichedContext.milestones}
101→${scenarioData ? `\n=== WHAT-IF SCENARIO RESULT (pre-computed, use these exact numbers) ===\n${scenarioData}` : ''}
102→
103→Instructions:
104→- You ONLY answer questions related to this loan, EMIs, interest, pre-payments, rate changes, and personal finance topics directly relevant to this loan. If the user asks anything unrelated (general knowledge, trivia, coding, etc.), politely decline and say you can only help with loan-related queries.
105→- All numbers above are EXACT and pre-computed. Present them directly — do NOT recalculate or round differently.
106→- For strategy/goal questions (e.g. "how to close my loan in X years"), use the pre-computed scenario data to give a clear actionable answer.
107→- Be SHORT and DIRECT. Answer only what was asked.
108→- Use INR (₹) formatting with Indian number system (lakhs, crores).
109→- For what-if scenarios, use ONLY the pre-computed scenario result above.
110→- Do NOT add motivational text, generic advice, or filler.
111→- If a one-line answer suffices, give a one-line answer.`;
112→
113→    const stream = await openai.chat.completions.create({
114→      model: 'gpt-4o-mini',
115→      messages: [
116→        { role: 'system', content: systemPrompt },
117→        ...messages.map((m) => ({ role: m.role as 'user' | 'assistant', content: m.content })),
118→      ],
119→      stream: true,
120→      max_tokens: 512,
121→    });
122→
123→    const encoder = new TextEncoder();
124→    const readable = new ReadableStream({
125→      async start(controller) {
126→        try {
127→          for await (const chunk of stream) {
128→            const content = chunk.choices[0]?.delta?.content;
129→            if (content) {
130→              controller.enqueue(encoder.encode(`data: ${JSON.stringify({ content })}\n\n`));
131→            }
132→          }
133→          controller.enqueue(encoder.encode('data: [DONE]\n\n'));
134→          controller.close();
135→        } catch {
136→          controller.close();
137→        }
138→      },
139→    });
140→
141→    return new Response(readable, {
142→      headers: {
143→        'Content-Type': 'text/event-stream',
144→        'Cache-Control': 'no-cache',
145→        Connection: 'keep-alive',
146→      },
147→    });
148→  } catch {
149→    return new Response(JSON.stringify({ error: 'Failed to process chat request' }), {
150→      status: 500,
151→      headers: { 'Content-Type': 'application/json' },
152→    });
153→  }
154→};
